built as (
  select
    s.id,
    1783632830262::bigint as updated_at,
    jsonb_build_object(
      'id', s.id,
      'nro', s.nro,
      'nombre', s.nombre,
      'grupo', s.grupo,
      'cuerpo', '',
      'parroquia', s.parroquia,
      'direccion', s.direccion,
      'mapsUrl', s."mapsUrl",
      'geom', case when s.lat is not null and s.lng is not null
        then jsonb_build_object('type','Point','coordinates', jsonb_build_array(s.lng, s.lat))
        else null end,
      'notas', s.notas,
      'fecha_levantamiento', '2026-07-09',
      'estado_federativo', s.estado_federativo,
      'municipio', s.municipio,
      'coord_politico', jsonb_build_object('ente','','cedula','','nombre','','telefono',''),
      'coord_ministerial', jsonb_build_object('ente', s.responsable, 'cedula','','nombre','','telefono',''),
      'seguridad', jsonb_build_object('cedula','','nombre','','telefono','','organismo','','vehiculos',0,'personal_mando',0),
      'servicios', jsonb_build_object('medicos',null,'psicologo',null,'ambulancias',null,'contacto_juez_paz',null),
      'total_afectados', 0,
      'censo_en_proceso', false,
      'novedades', '',
      'supervision', jsonb_build_object('telefono','','unidad_sebin','','supervisor_sebin',''),
      'requerimientos', '[]'::jsonb,
      'capacidad', jsonb_build_object(
        'agua_litros',0,'agua_tanque',false,'agua_operativa',false,
        'camas_instaladas',0,'camas_operativas',0,
        'duchas_instaladas',0,'duchas_operativas',0,
        'pocetas_instaladas',0,'pocetas_operativas',0,
        'lavaderos_instalados',0,'lavaderos_operativos',0,
        'contenedores_instalados',0,'contenedores_operativos',0
      ),
      'ocupacion', jsonb_build_object(
        'ninas',0,'ninos',0,'mascotas',0,
        'adultos_h',0,'adultos_m',0,'embarazadas',0,
        'adolescentes_h',0,'adolescentes_m',0,
        'discapacidad_h',0,'discapacidad_m',0,
        'recien_nacidos_h',0,'recien_nacidos_m',0,
        'adultos_mayores_h',0,'adultos_mayores_m',0
      ),
      'personal', jsonb_build_object(
        'medicos',0,'psicologos',0,'justicia_mp',0,
        'funcionarios',0,'justicia_tjs',0,'trabajadores',0,'justicia_defensoria',0
      ),
      'familias_ocupadas', 0,
      'responsables', '[]'::jsonb,
      'responsables_coordinacion', '[]'::jsonb,
      'foto_url', '',
      'estado', 'preparacion',
      'deleted', false,
      'updated_at', 1783632830262,
      'updated_by', 'admin'
    ) as data,
    case when s.lat is not null and s.lng is not null
      then ST_SetSRID(ST_MakePoint(s.lng, s.lat), 4326)::geography
      else null end as geom
  from seed s
)
insert into public.centros (id, updated_at, updated_by, deleted, data, geom)
select id, updated_at, 'admin', false, data, geom
from built
on conflict (id) do nothing
returning id, data->>'nombre' as nombre, geom is not null as tiene_geom;
